import{_ as e,c as t,o as s,a2 as i}from"./chunks/framework.CIiVzG-O.js";const k=JSON.parse('{"title":"マルチプレイゲームをホストする","description":"","frontmatter":{},"headers":[],"relativePath":"akashic-system/index.md","filePath":"akashic-system/index.md"}'),r={name:"akashic-system/index.md"};function c(o,a,l,n,h,p){return s(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="マルチプレイゲームをホストする" tabindex="-1">マルチプレイゲームをホストする <a class="header-anchor" href="#マルチプレイゲームをホストする" aria-label="Permalink to &quot;マルチプレイゲームをホストする&quot;">​</a></h1><p>Akashic Engine で作成されたゲームは、以下の方法で公開することができます。</p><ul><li>HTML 形式に変換 (<a href="./../tutorial/v3/export.html">Akashic Engine 入門 » シングルプレイのゲーム作成 » ゲームを公開する</a>)</li><li>ニコ生ゲームとして投稿 (<a href="./../shin-ichiba/submit.html">ニコ生ゲームを作ろう » ニコ生ゲームを投稿しよう</a>)</li></ul><p>しかし <strong>マルチプレイゲームは、これらの方法では公開できません</strong> 。 プレイヤー間の通信を行う専用のサーバプログラムなどが必要になるためです。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>ニコ生ゲームのマルチプレイゲーム対応は、2026 年 2 月をもって終了しました。</p></div><p>2026 年現在、マルチプレイゲームを公開する公式の・手軽な方法はありません。 ただし技術的には、Akashic System を活用して自力でサーバを構築することができます。</p><h2 id="akashic-system" tabindex="-1">Akashic System とオールインワン環境 <a class="header-anchor" href="#akashic-system" aria-label="Permalink to &quot;Akashic System とオールインワン環境 {#akashic-system}&quot;">​</a></h2><p><strong><a href="https://github.com/akashic-games/akashic-system" target="_blank" rel="noreferrer">Akashic System</a></strong> は、ニコ生ゲームのサーバ側実装として実際に利用されてきたプログラム群です。 ニコ生ゲームのマルチプレイ対応終了に伴い、オープンソースのフリーソフトウェアとして公開されました。利用にロイヤリティは必要ありません。</p><p>Akashic System は、WebSocket ベースの通信サーバやリプレイデータを保持するデータベース、JavaScript ゲーム実行系など、複数のサーバとミドルウェアから成り立ちます。 ただしそれらの詳細は文書化されていません。</p><p>代わりにここでは、それらを一式まとめた Docker コンテナ群 (<strong>オールインワン環境</strong>) を起動する手順を紹介します。 オールインワン環境を使えば、マルチプレイの Akashic ゲームをホストするデモサーバを比較的簡単に作成できます。</p><p>なおオールインワン環境の利用にあたっては、以下について基本的な知識が必要です。</p><ul><li>Git, Docker, Linux</li><li>HTTP サーバなどの一般的な Web 開発</li><li>TypeScript, Node.js (コードに手を入れる場合)</li></ul>',12)])])}const d=e(r,[["render",c]]);export{k as __pageData,d as default};
